import { Component } from '@angular/core';

interface DocItem {
  title: string;
  description?: string;
  content?: string;
  href?: string;
}

interface DocCategory {
  id: string;
  name: string;
  count: number;
  documents: DocItem[];
}

@Component({
  selector: 'app-documentation',
  standalone: true,
  imports: [],
  templateUrl: './documentation.component.html',
  styleUrls: ['./documentation.component.scss']
})
export class DocumentationComponent {
  selectedCategoryIndex = 0;
  selectedDocIndex = 0;

  docCategories: DocCategory[] = [
    {
      id: 'user-manual',
      name: 'User manual',
      count: 3,
      documents: [
        {
          title: "Manuel d'utilisateur – Taxateur",
          description: 'Guide opérationnel pour les agents chargés de la taxation et de la liquidation des droits et redevances.',
          content: 'Statement of reasons. This user manual describes the procedures for assessors (taxateurs) in charge of taxation and liquidation of duties and fees within the DGRAD framework.',
          href: '#'
        },
        {
          title: "Manuel d'utilisateur – Contrôleurs",
          description: 'Procédures de contrôle et de vérification des opérations de mobilisation des recettes non fiscales.',
          content: 'Statement of reasons. This manual defines control and verification procedures for non-tax revenue mobilization operations.',
          href: '#'
        },
        {
          title: "Manuel d'utilisateur – Logiciel",
          description: 'Documentation fonctionnelle sur l\'outil informatique utilisé pour la gestion des recettes non fiscales.',
          content: 'Statement of reasons. Functional documentation of the LOGIRAD software: modules, user profiles, security and key business processes.',
          href: '#'
        }
      ]
    },
    {
      id: 'orders',
      name: 'Orders',
      count: 1,
      documents: [
        {
          title: 'Order No. 003 of September 20, 2018, concerning the internal regulations of the Court of Cassation',
          description: 'Internal regulations of the Court of Cassation.',
          content: 'Statement of reasons. This order sets out the internal regulations of the Court of Cassation. It defines the organization, operation and rules applicable to the Court.',
          href: '#'
        }
      ]
    },
    {
      id: 'decrees',
      name: 'Decrees',
      count: 1,
      documents: [
        {
          title: 'Ordonnance-loi n°13/003 du 23 février 2013',
          description: 'Réforme des procédures d\'assiette, de contrôle et de recouvrement des recettes non fiscales.',
          content: 'Statement of reasons. This ordinance-law reforms the procedures for assessment, control and recovery of non-tax revenues. It establishes the framework for DGRAD and LOGIRAD operations.',
          href: 'https://dgrad.gouv.cd'
        }
      ]
    },
    {
      id: 'circulars',
      name: 'Circulars',
      count: 2,
      documents: [
        {
          title: 'Circular on the application of LOGIRAD in the provinces',
          description: 'Guidelines for provincial deployment.',
          content: 'Statement of reasons. This circular provides guidelines for the extension of the LOGIRAD paperless procedure across the provinces.',
          href: '#'
        },
        {
          title: 'Circular on user access and security',
          description: 'Security and access rules for LOGIRAD users.',
          content: 'Statement of reasons. This circular defines security, warnings and precautions for all authorized LOGIRAD users.',
          href: '#'
        }
      ]
    },
    {
      id: 'others',
      name: 'Others',
      count: 0,
      documents: []
    }
  ];

  docs = [
    {
      category: 'Guides utilisateurs',
      items: [
        {
          title: "Manuel d’utilisateur – Taxateur",
          description:
            'Guide opérationnel pour les agents chargés de la taxation et de la liquidation des droits et redevances.',
          href: '#'
        },
        {
          title: "Manuel d’utilisateur – Contrôleurs",
          description:
            'Procédures de contrôle et de vérification des opérations de mobilisation des recettes non fiscales.',
          href: '#'
        },
        {
          title: "Manuel d’utilisateur – Logiciel",
          description:
            'Documentation fonctionnelle sur l’outil informatique utilisé pour la gestion des recettes non fiscales.',
          href: '#'
        }
      ]
    },
    {
      category: 'Textes réglementaires',
      items: [
        {
          title: 'Ordonnance-loi n°13/003 du 23 février 2013',
          description:
            'Réforme des procédures d’assiette, de contrôle et de recouvrement des recettes non fiscales.',
          href: 'https://dgrad.gouv.cd'
        },
        {
          title: 'Code Minier (2002, tel que modifié en 2018)',
          description:
            'Dispositions relatives au partage des recettes minières et au rôle de la DGRAD dans la quote-part de l’État.',
          href: 'https://dgrad.gouv.cd'
        }
      ]
    }
  ];

  profiles = [
    {
      name: 'Administrator',
      description:
        'Creates users, resets passwords and configures reference data such as generating acts, rates, sectors, services, management rules and penalties.'
    },
    {
      name: 'Assessor',
      description:
        'Manages the subject registry, records declarations and creates tax assessments for the assessment services.'
    },
    {
      name: 'Chief Assessor',
      description:
        'Validates or rejects tax assessment notes issued by assessors within the same assessment service.'
    },
    {
      name: 'Controller',
      description:
        'Controls authorisations and records conformity/non‑conformity reports, with access to taxation, authorisation and payment registers.'
    },
    {
      name: 'Authorising Officer',
      description:
        'Issues and manages payment notices and payment orders, and consults related registers, including special and ex‑officio authorisations.'
    },
    {
      name: 'Receiver',
      description:
        'Handles recovery, clearance, enforcement actions, discharge certificates and monitoring of outstanding balances and rolls.'
    },
    {
      name: 'Consultation',
      description:
        'Read‑only profile providing access to key registers such as taxation, authorisation and payment without the ability to modify data.'
    }
  ];

  securityPoints = [
    'Keep your LOGIRAD credentials (email address and password) strictly confidential and never share them.',
    'Use a strong, complex and regularly updated password to protect access to the application.',
    'Ensure you use a secure, trusted computer and internet connection when accessing LOGIRAD.',
    'Only enter valid and authorised data in accordance with the procedures of the DGRAD and the Ministry of Finance.'
  ];

  /** Cards for General information – integrated LOGIRAD services (subjects, declarations, files, taxation, authorizations, control, recovery, litigation) */
  moduleCards = [
    { icon: '👤', title: 'Subjects', items: ['Registry of natural persons, legal entities and NGOs', 'Addresses and identifiers for declarations and taxations'] },
    { icon: '📋', title: 'Declarations', items: ['Links subjects to periodic taxes', 'Records assessments and identifies filed declarations and defaulters'] },
    { icon: '📁', title: 'Files', items: ['Tracks requests and supporting documents', 'From reception to use for declarations or taxations'] },
    { icon: '💰', title: 'Taxation', items: ['Tax assessment notes (ordinary, ex‑officio, regularisation)', 'Attachments and validation'] },
    { icon: '✅', title: 'Authorizations', items: ['Payment notices and payment orders', 'Special and ex‑officio authorisations'] },
    { icon: '🔍', title: 'Control', items: ['Compliance of authorisations and tax assessments', 'Targeted control missions'] },
    { icon: '📥', title: 'Recovery', items: ['Uptake of authorised revenues', 'Clearance, discharge certificates, rolls, enforcement'] },
    { icon: '⚖️', title: 'Litigation', items: ['Administrative and judicial appeals', 'Effects of complaints and decisions on notices and amounts due'] }
  ];

  processes = [
    {
      title: 'Subject management',
      summary:
        'Registers and updates subjects (natural persons, legal entities and NGOs), with addresses and identifiers, which are the basis for declarations and taxations.'
    },
    {
      title: 'Declaration management',
      summary:
        'Links subjects to periodic taxes, records assessments (simple or multiple) and identifies filed declarations, defaulters and potential defaulters.'
    },
    {
      title: 'File management',
      summary:
        'Tracks subject requests and supporting documents through files, from reception and acknowledgement of receipt to their use for declarations or taxations.'
    },
    {
      title: 'Taxation management',
      summary:
        'Creates and manages tax assessment notes (ordinary, based on declarations, with sites, ex‑officio and regularisation), including attachments and validation.'
    },
    {
      title: 'Authorisation management',
      summary:
        'Produces and manages payment notices and payment orders, including rejected and cancelled notices, and special or ex‑officio authorisations.'
    },
    {
      title: 'Control management',
      summary:
        'Ensures that authorisations and tax assessments comply with legal and regulatory requirements through targeted control missions.'
    },
    {
      title: 'Recovery and clearance',
      summary:
        'Covers uptake of authorised revenues, confirmation of payments, clearance of payment notices, discharge certificates, rolls, final notices and enforcement.'
    },
    {
      title: 'Disputes management',
      summary:
        'Manages administrative and judicial appeals relating to taxations and recoveries, including the effects of complaints and decisions on notices and amounts due.'
    }
  ];

  selectCategory(index: number): void {
    this.selectedCategoryIndex = index;
    this.selectedDocIndex = 0;
  }

  selectDocument(index: number): void {
    this.selectedDocIndex = index;
  }

  get selectedCategory(): DocCategory {
    return this.docCategories[this.selectedCategoryIndex] ?? this.docCategories[0];
  }

  get selectedDocument(): DocItem | null {
    const cat = this.selectedCategory;
    const docs = cat.documents;
    if (docs.length === 0) return null;
    return docs[this.selectedDocIndex] ?? docs[0];
  }
}

<!-- ── First section: same layout as Contact US ───────── -->
<section class="page-hero page-hero--contact-style">
  <div class="hero-bg" style="background-image: url('assets/DOCUMENTATION-bb206954-fb72-4632-a1b3-97f01e747348.png');"></div>
  <div class="hero-overlay"></div>
  <div class="container hero-inner">
    <div class="hero-left-block">
      <h1>DOCUMENTATION</h1>
    </div>
    <div class="hero-divider"></div>
    <div class="hero-right-block">
      <p>Official resources and documents of LOGIRAD.<br/>User manuals, regulatory texts and support.</p>
    </div>
  </div>
</section>

<!-- ── General information: text block only, no cards ─── -->
<section class="docs-extra docs-extra--text-block">
  <div class="container container--narrow">
    <div class="section-header-center">
      <div class="section-kicker">General information</div>
      <h2 class="section-title">INTEGRATED LOGIRAD SERVICES</h2>
      <p class="section-sub">
        LOGIRAD centralizes the main modules described in the user manual: subjects, declarations, files,
        taxation, authorizations, control, recovery and litigation.
      </p>
    </div>
  </div>
</section>

<!-- ── User profiles: text block only, no cards ───────── -->
<section class="docs-extra docs-extra--text-block">
  <div class="container container--narrow">
    <div class="section-header-center">
      <div class="section-kicker">User profiles</div>
      <h2 class="section-title">User profiles in LOGIRAD</h2>
      <p class="section-sub">
        Access is strictly controlled through predefined user profiles, each with specific responsibilities and permissions.
      </p>
    </div>
  </div>
</section>

<!-- ── Security & access: text block + bullet list; only resource links in card ── -->
<section class="docs-extra docs-extra--text-block">
  <div class="container container--narrow">
    <div class="section-header-center">
      <div class="section-kicker">Security &amp; access</div>
      <h2 class="section-title">Security, warnings and precautions</h2>
      <p class="section-sub">
        The manuals insist on a secure and responsible use of LOGIRAD by all authorized users.
      </p>
    </div>
    <ul class="bullet-list bullet-list--standalone">
      <li *ngFor="let item of securityPoints">{{ item }}</li>
    </ul>
    <div class="resource-links-card">
      <p class="resource-links-item">
        LOGIRAD web application:
        <a href="https://logirad.dgrad.cd" target="_blank" rel="noopener">https://logirad.dgrad.cd</a>
      </p>
      <p class="resource-links-item">
        Latest manuals and resources:
        <a href="http://portail.dgrad.cd" target="_blank" rel="noopener">portail.dgrad.cd</a>
      </p>
      <p class="resource-links-item">
        Technical support:
        <a href="mailto:support.logirad&#64;dgrad.cd">support.logirad&#64;dgrad.cd</a>
      </p>
    </div>
  </div>
</section>

<!-- ── Processes: text block only, no cards ────────────── -->
<section class="docs-extra docs-extra--text-block">
  <div class="container container--narrow">
    <div class="section-header-center">
      <div class="section-kicker">Processes</div>
      <h2 class="section-title">Key business processes</h2>
      <p class="section-sub">
        LOGIRAD structures the revenue chain into a series of linked processes, from subject registration to dispute resolution.
      </p>
    </div>
  </div>
</section>

<!-- ── Resources / Documentation Center: header + two-column (categories | doc list/content) ── -->
<section class="docs-extra docs-extra--centre">
  <div class="container">
    <div class="section-header-center">
      <div class="section-kicker">Resources</div>
      <h2 class="section-title">Documentation Center</h2>
      <p class="section-sub">
        Official resources and documents of LOGIRAD.
      </p>
    </div>
    <div class="doc-viewer">
      <div class="doc-viewer-left">
        <div
          *ngFor="let cat of docCategories; let i = index"
          class="doc-category-row"
          [class.is-selected]="selectedCategoryIndex === i"
          (click)="selectCategory(i)"
        >
          <span class="doc-category-name">{{ cat.name }}</span>
          <span class="doc-category-count">{{ cat.count }}</span>
          <span class="doc-category-arrow">›</span>
        </div>
      </div>
      <div class="doc-viewer-right">
        <ng-container *ngIf="selectedCategory.documents.length > 0">
          <div class="doc-list-pane" *ngIf="selectedDocument === null || (selectedCategory.documents.length > 0 && selectedDocIndex >= 0)">
            <button
              *ngFor="let doc of selectedCategory.documents; let i = index"
              type="button"
              class="doc-list-item"
              [class.is-selected]="selectedDocIndex === i"
              (click)="selectDocument(i)"
            >
              {{ doc.title }}
              <span class="doc-list-arrow">›</span>
            </button>
          </div>
          <div class="doc-content-pane" *ngIf="selectedDocument as doc">
            <h3 class="doc-content-title">{{ doc.title }}</h3>
            <p class="doc-content-body">{{ doc.content || doc.description }}</p>
            <a *ngIf="doc.href && doc.href !== '#'" [href]="doc.href" target="_blank" rel="noopener" class="doc-content-download">Télécharger</a>
          </div>
        </ng-container>
        <div *ngIf="selectedCategory.documents.length === 0" class="doc-empty">
          <p>No documents in this category.</p>
        </div>
      </div>
    </div>
  </div>
</section>
